class QuantileExploration:
    def __init__(self, alpha: float):
        self.alpha = alpha  # quantile (e.g., 0.95)

    def __call__(self, model):
        return np.argmax([distrib.ppf(self.alpha) for distrib in model.B])

Quantile exploration, which returns the action with the highest α quantile.

class QuantileExploration(BanditPolicy):
    def __init__(self, alpha: float):
        self.alpha = alpha  # quantile (e.g., 0.95)

    def __call__(self, model: BanditModel) -> int:
        return np.argmax([distrib.ppf(self.alpha) for distrib in model.B])

A method for estimating a policy gradient of a policy π(s) for an MDP P with initial state distribution b using the likelihood ratio trick. The gradient with respect to the parameterization vector θ is estimated from m rollouts to depth d using the log policy gradients ∇ log π.

class LikelihoodRatioGradient(PolicyGradientEstimationMethod):
    def __init__(self, P: MDP, b: np.ndarray, d: int, m: int, grad_logpi: Callable[[np.ndarray, Any, Any], np.ndarray]):
        self.P = P                  # problem
        self.b = b                  # initial state distribution
        self.d = d                  # depth
        self.m = m                  # number of samples
        self.grad_logpi = grad_logpi  # gradient of log likelihood

    def gradient(self, policy: Callable[[np.ndarray, Any], Any], theta: np.ndarray) -> np.ndarray:
        P, b, d, m, grad_logpi, gamma = self.P, self.b, self.d, self.m, self.grad_logpi, self.P.gamma
        def policy_theta(s): return policy(theta, s)
        def R(tau): return np.sum([r*(gamma**k) for (k, (s, a, r)) in enumerate(tau)])
        def grad_U(tau): return np.sum([grad_logpi(theta, a, s) for (s, a, r) in tau], axis=0) * R(tau)
        return np.mean([grad_U(simulate(P, random.choices(P.S, weights=b)[0], policy_theta, d)) for i in range(m)], axis=0)

The sparse sampling algorithm for finding an approximately optimal action online for a discrete problem P from a current state s to depth d with m samples per action. The returned tuple consists of the best action a and its finite-horizon expected value u.

def sparse_sampling(P: MDP, s: Any, d: int, m: int, U: Callable[[Any], float]):
    if d <= 0:
        return (None, U(s))
    best_a, best_u = (None, -np.inf)
    for a in P.A:
        u = 0.0
        for _ in range(m):
            s_prime, r = P.randstep(s, a)
            a_prime, u_prime = sparse_sampling(P, s_prime, d - 1, m, U)
            u += (r + P.gamma * u_prime) / m
        if u > best_u:
            best_a, best_u = (a, u)
    return best_a, best_u


class SparseSampling(OnlinePlanningMethod):
    def __init__(self, P: MDP, d: int, m: int, U: Callable[[Any], float]):
        self.P = P  # problem
        self.d = d  # depth
        self.m = m  # number of samples
        self.U = U  # value function at depth d

    def __call__(self, s: Any) -> Any:
        return (sparse_sampling(self.P, s, self.d, self.m, self.U))[0]
